const a = [
  {"id":3430,"text":"Which of the following secretes androgens?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 956.","responses":[{"text":"All of these","correct":false,"visible":false},{"text":"Zona fasciculata","correct":false,"visible":false},{"text":"Zona glomerulosa","correct":false,"visible":false},{"text":"Zona reticularis","correct":true,"visible":false},{"text":"Adrenal medulla","correct":false,"visible":false}]},{"id":5444,"text":"Parathyroid adenoma most commonly involves which of the following sites?","explanation":null,"reference":null,"responses":[{"text":"Superior parathyroid lobe","correct":false,"visible":false},{"text":"Thymus","correct":false,"visible":false},{"text":"In the mediastinum","correct":false,"visible":false},{"text":"Inferior parathyroid lobe","correct":true,"visible":false},{"text":"Thyroid substance","correct":false,"visible":false}]},{"id":5621,"text":"A 35-year-old woman presents with a serum calcium level of 15.2 mg/dL and an elevated parathyroid hormone level. Following correction of the patient’s hypercalcemia with hydration and furosemide, which of the following is the best therapeutic approach?","explanation":null,"reference":null,"responses":[{"text":"Neck exploration and resection of a parathyroid adenoma","correct":true,"visible":false},{"text":"Radiation treatment to the neck","correct":false,"visible":false},{"text":"Administration of steroids","correct":false,"visible":false},{"text":"Neck exploration and resection of all 4 parathyroid glands","correct":false,"visible":false},{"text":"Avoidance of sunlight, vitamin D, and calcium-containing dairy products","correct":false,"visible":false}]},{"id":7996,"text":"A 46-year-old man is newly diagnosed with type 2 diabetes. He is advised to exercise regularly by his physician. Which of the following is not a beneficial effect of exercise in people with diabetes?","explanation":null,"reference":null,"responses":[{"text":"Increase of insulin sensitivity","correct":false,"visible":false},{"text":"Reduction of triglycerides","correct":false,"visible":false},{"text":"Reduction of cholesterol","correct":false,"visible":false},{"text":"Hypoglycemia","correct":true,"visible":false},{"text":"Help controlling hypertension","correct":false,"visible":false}]},{"id":7998,"text":"Which of the following is incorrectly matched with its mechanism?","explanation":null,"reference":null,"responses":[{"text":"Biguanides: decreases hepatic gluconeogenesis","correct":false,"visible":false},{"text":"Alpha glucosidase inhibitors: decrease GIT absorption of glucose","correct":false,"visible":false},{"text":"Meglitinides: increase release of insulin","correct":false,"visible":false},{"text":"Sulfonylureas: block ATP dependent potassium channels","correct":false,"visible":false},{"text":"Thiazolidinediones: PPAR-λ receptor antagonist","correct":true,"visible":false}]},{"id":7999,"text":"Which type of hyperparathyroidism is a physiological response of the parathyroid gland to hypocalcemia?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 353.","responses":[{"text":"Parathyroid hyperplasia","correct":false,"visible":false},{"text":"Parathyroid adenoma","correct":false,"visible":false},{"text":"Primary hyperparathyroidism","correct":false,"visible":false},{"text":"Secondary hyperparathyroidism","correct":true,"visible":false},{"text":"Tertiary hyperparathyroidism","correct":false,"visible":false}]},{"id":8024,"text":"A 20-year-old woman is referred to the endocrinology clinic after a history of persistent headaches over the last 1 year. Her examination shows evidence of a left temporal visual field defect. Subsequent anterior pituitary functions tests confirm secondary hypothyroidism and hypogonadotropic hypogonadism. MRI of the pituitary shows a 4 × 2 cm cystic calcified parasellar lesion, which is compressing the optic chiasm. The cyst is radiologically described as showing the appearance of engine oil. Which one of the following is the likely diagnosis based on her clinical profile?","explanation":null,"reference":null,"responses":[{"text":"Craniopharyngioma","correct":true,"visible":false},{"text":"Neurosarcoidosis","correct":false,"visible":false},{"text":"Germinoma","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false},{"text":"Teratoma","correct":false,"visible":false}]},{"id":8025,"text":"What is the mechanism of action of sermorelin?","explanation":null,"reference":null,"responses":[{"text":"It increases the expression of growth hormone receptors","correct":false,"visible":false},{"text":"It replaces growth hormone","correct":false,"visible":false},{"text":"It activates the growth hormone receptors","correct":false,"visible":false},{"text":"It stimulates growth hormone release","correct":true,"visible":false},{"text":"It directly increases the levels of IGF-1","correct":false,"visible":false}]},{"id":8026,"text":"A 60-year-old male presents with end-stage renal disease, hyperkalemia, and metabolic acidosis. He also has hyperparathyroidism as a physiological response to hypocalcemia. What is the patient suffering from?","explanation":null,"reference":null,"responses":[{"text":"Secondary hyperparathyroidism","correct":true,"visible":false},{"text":"Parathyroid hyperplasia","correct":false,"visible":false},{"text":"Parathyroid adenoma","correct":false,"visible":false},{"text":"Primary hyperparathyroidism","correct":false,"visible":false},{"text":"Tertiary hyperparathyroidism","correct":false,"visible":false}]},{"id":8027,"text":"Which of the following statements is NOT true about the pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Pars intermedia is concerned with secreting melanocyte stimulating hormone (MSH)","correct":false,"visible":false},{"text":"Anterior pituitary develops from Rathke’s pouch","correct":false,"visible":false},{"text":"Hypophyseal portal system is responsible for carrying released hormones to the anterior pituitary","correct":false,"visible":false},{"text":"Pituicytes in the posterior pituitary are responsible for secreting oxytocin and ADH","correct":true,"visible":false},{"text":"Pars distalis is part of anterior pituitary","correct":false,"visible":false}]},{"id":8028,"text":"A 34-year-old female presents with a complaint of neck swelling for the past 6 months which has slightly increased in size. She has a history of weight gain. On clinical examination, her pulse is 80 beats/min, her blood pressure is 110/70 mmHg, and she is afebrile. Her neck examination reveals diffuse but non-tender swelling which moves on deglutition. Thyroid function test shows TSH = 3.0 mIU/L, Free T4 = 0.8 ng/dL. What would be the most appropriate initial investigation in this patient?","explanation":null,"reference":null,"responses":[{"text":"X-ray neck","correct":false,"visible":false},{"text":"Computed tomography (CT) scan neck","correct":false,"visible":false},{"text":"Magnetic resonance imaging (MRI) neck","correct":false,"visible":false},{"text":"Thyroid scan","correct":false,"visible":false},{"text":"Ultrasound neck","correct":true,"visible":false}]},{"id":8029,"text":"A male was caught red-handed while robbing a chemical store at Jodia bazaar. A mob was gathered and started brutal violence against the robber. One of the men bought a chemical from the nearby store and forced the robber to drink it. The helpless person did as directed, and after a few minutes developed severe convulsions, cyanosis, and dyspnea. Blood-stained froth could be seen in his mouth. What is the most likely cause of poisoning?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015:  600.","responses":[{"text":"Organophosphorus","correct":true,"visible":false},{"text":"Dichlorodiphenyltrichloroethane (DDT)","correct":false,"visible":false},{"text":"Corrosive acid","correct":false,"visible":false},{"text":"Bleach","correct":false,"visible":false},{"text":"Paraquat","correct":false,"visible":false}]},{"id":8030,"text":"A 36-year-old woman was incidentally detected to have a 6 mm pituitary microadenoma on computed tomography (CT) scan of the head, performed to evaluate the causes for her recurrent headaches. Apart from the headaches that she had suffered for the last 6 months, she had no past history of any significant medical illness and was not on any regular medications. Her general physical and systemic examination was unremarkable. Which of the following is the most appropriate next step in her management?","explanation":null,"reference":null,"responses":[{"text":"Formal visual field assessment","correct":false,"visible":false},{"text":"Neurosurgical referral","correct":false,"visible":false},{"text":"Discharge from follow-up","correct":false,"visible":false},{"text":"Insulin tolerance test","correct":false,"visible":false},{"text":"Anterior pituitary hormone profile","correct":true,"visible":false}]},{"id":8031,"text":"Thyroid hormone increases the activity of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Na+/K+ ATPase pump","correct":true,"visible":false},{"text":"K+ leak channels","correct":false,"visible":false},{"text":"Na+/ Ca2+ pump","correct":false,"visible":false},{"text":"Na+ leak channels","correct":false,"visible":false},{"text":"Na+/K+/2Cl– pump","correct":false,"visible":false}]},{"id":8032,"text":"A 16-year-old male is diagnosed with type 1 diabetes. He is kept on insulin for the future. Insulin deficiency is associated with which of the following?","explanation":null,"reference":"Dhillon KK, Gupta S. Biochemistry, ketogenesis. In: StatPearls. StatPearls Publishing; 2022. Accessed July 3, 2022. http://www.ncbi.nlm.nih.gov/books/NBK493179/","responses":[{"text":"Increased ketogenesis","correct":true,"visible":false},{"text":"Reduced proteolysis","correct":false,"visible":false},{"text":"Decreased ketogenesis","correct":false,"visible":false},{"text":"Reduced gluconeogenesis","correct":false,"visible":false},{"text":"Reduced lipolysis","correct":false,"visible":false}]},{"id":8033,"text":"A 28-year-old man presents to the emergency department with a severe headache and vision problems over the last 6 months. Head computed tomography (CT) reveals a large sellar mass extending to the suprasellar region and distorting the optic chiasm. He also describes reduced libido and sexual dysfunction for the last 1 year. On physical examination, he appears healthy and vitally stable. Findings on neurologic examination are normal, except for bitemporal hemianopsia. Laboratory test results (blood drawn at 8 am): TSH = 1.0 miU/L (0.4-4.0), FT4 = 0.9 ng/dL (0.86-1.76), cortisol = 18.0 ug/dL (5-25), prolactin = 1280 ng/mL (19-23), growth hormone (GH) = 0.5 ng/mL. (2-5) What is the most likely cause of his sellar mass?","explanation":null,"reference":null,"responses":[{"text":"Craniopharyngioma","correct":false,"visible":false},{"text":"Pituitary hemorrhage","correct":false,"visible":false},{"text":"Non-functioning pituitary adenoma","correct":false,"visible":false},{"text":"Growth hormone secreting adenoma","correct":false,"visible":false},{"text":"Prolactinoma","correct":true,"visible":false}]},{"id":8034,"text":"A 17-year-old boy is admitted to the intensive care unit with complaints of diarrhea, vomiting, and abdominal pain. He was diagnosed with a hormonal deficiency by his primary physician and instructed to remain on hydrocortisone pills for his whole life. Unfortunately, due to the recent COVID-19 pandemic, he could not get his adequate supply and stopped taking the pills for almost 15 days. What is his current diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Food poisoning","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":false,"visible":false},{"text":"Acute gastroenteritis","correct":false,"visible":false},{"text":"Thyroid storm","correct":false,"visible":false},{"text":"Addisonian crisis","correct":true,"visible":false}]},{"id":8035,"text":"A 20-day-old baby is brought to the neonatal intensive care unit (NICU) with complaints of vomiting for 2 days. On examination, the baby is severely dehydrated, heart rate is 165 beats/min, respiratory rate is 68 breaths/min, and the temperature is 98 F. Arterial blood gases (ABGs) reveal severe metabolic acidosis, Na = 120 mEq/L, K = 5.8 mEq/L, urea = 62 mg/dL, Cr = 1.0 mg/dL, and random blood sugar (RBS) = 30 mg/dL. What is the most likely diagnosis?","explanation":null,"reference":"(1) Khan PA. Basis of Pediatrics. 10th ed. Paramount Books (Pvt.) Ltd; 2018: 462.\r\n\r\n(2) Endocrinology-2 module; Medicine lecture slides, Topic: Disorders of the adrenal gland, Sub-topic: Addisonian crisis.","responses":[{"text":"Acute renal tubular acidosis","correct":false,"visible":false},{"text":"Congenital adrenal hyperplasia","correct":true,"visible":false},{"text":"Diabetic ketoacidosis","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Neonatal sepsis","correct":false,"visible":false}]},{"id":8046,"text":"Which one of the following thyroid inhibitors interferes with peripheral conversion of thyroxine into triiodothyronine?","explanation":null,"reference":null,"responses":[{"text":"Carbimazole","correct":false,"visible":false},{"text":"Ethacrynic acid","correct":false,"visible":false},{"text":"Radioactive iodine","correct":false,"visible":false},{"text":"Lugol’s iodine","correct":false,"visible":false},{"text":"Propylthiouracil","correct":true,"visible":false}]},{"id":8047,"text":"An obese patient, who has diabetes type 2, needs an oral hypoglycemic. What is the recommended drug for him?","explanation":null,"reference":null,"responses":[{"text":"Miglitol","correct":false,"visible":false},{"text":"Glyburide","correct":false,"visible":false},{"text":"Glimepiride","correct":false,"visible":false},{"text":"Pioglitazone","correct":false,"visible":false},{"text":"Metformin","correct":true,"visible":false}]},{"id":8048,"text":"A medical student of 2nd-year MBBS was given a slide of the endocrine gland. He noticed a large number of round to oval structures lined by simple cuboidal epithelium. What is the most likely structure that was observed?","explanation":null,"reference":null,"responses":[{"text":"Parathyroid gland","correct":false,"visible":false},{"text":"Pituitary gland","correct":false,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Thyroid gland","correct":true,"visible":false},{"text":"Pancreas","correct":false,"visible":false}]},{"id":8050,"text":"Osteoporosis is a major adverse effect caused by glucocorticoids. Which of the following correctly explains this?","explanation":null,"reference":null,"responses":[{"text":"Stimulation of the hypophyseal-pituitary-adrenal (HPA) axis","correct":false,"visible":false},{"text":"Increased excretion of calcium","correct":false,"visible":false},{"text":"Inhibition of calcium absorption","correct":true,"visible":false},{"text":"Decreased production of prostaglandins","correct":false,"visible":false},{"text":"Decreased collagen synthesis","correct":false,"visible":false}]},{"id":8051,"text":"Following a bone fracture, it is found that the patient's parathyroid and calcium levels are low while phosphorus levels are high. What is the most common cause of this condition?","explanation":null,"reference":null,"responses":[{"text":"Adenoma","correct":false,"visible":false},{"text":"Thyroid surgery","correct":true,"visible":false},{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Renal failure","correct":false,"visible":false}]},{"id":8052,"text":"A 66-year-old woman is complaining of abdominal pain, constipation. In the past, she underwent renal stone surgery. On examination, her blood pressure (BP) is 145/77 mmHg and her pulse is 98 beats/min. Her fasting glucose and kidney function tests are normal but her calcium is found to be elevated at 13.05 mg/dL. What is the most likely cause of her hypercalcemia?","explanation":null,"reference":"FA 2021 pg 352-353","responses":[{"text":"Primary hyperparathyroidism","correct":true,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Growth hormone excess","correct":false,"visible":false},{"text":"Thiazide diuretics","correct":false,"visible":false},{"text":"Vitamin D intoxication","correct":false,"visible":false}]},{"id":8053,"text":"A 40-year-old female presents to the clinic with diffuse neck swelling for the last year, which is increasing in size. She is asked her to raise her arms above the head with elbows touching the ears. A couple of seconds later, her face turns red. What is this clinical sign known as?","explanation":null,"reference":null,"responses":[{"text":"Von Graefe’s sign","correct":false,"visible":false},{"text":"Berry’s sign","correct":false,"visible":false},{"text":"Pemberton’s sign","correct":true,"visible":false},{"text":"Moebius’s sign","correct":false,"visible":false},{"text":"Joffrey’s sign","correct":false,"visible":false}]},{"id":8054,"text":"Students of 2nd-year MBBS are given a slide of the pancreas for study. The endocrine part shows islets of Langerhans with different types of cells. What cells of the pancreas secrete pancreatic polypeptide?","explanation":"Gamma cells are endocrine cells located in the islets of Langerhans of the pancreas that produce pancreatic polypeptide (PP) which regulates pancreatic secretion, gut motility, and appetite, and is associated with diabetes and obesity.","reference":null,"responses":[{"text":"Gamma cells","correct":true,"visible":false},{"text":"Beta cells","correct":false,"visible":false},{"text":"Islets of Langerhans","correct":false,"visible":false},{"text":"Delta cells","correct":false,"visible":false},{"text":"Alpha cells","correct":false,"visible":false}]},{"id":8055,"text":"A 6-year-old child is brought to the emergency department with complaints of abdominal pain and vomiting. He was previously healthy but has a history of easy fatigability, weight loss, and increased thirst. On examination, heart rate is 145 beats/min, respiratory rate is 50 breaths/min, and temperature is 98 F. Chest is clear on auscultation. On investigations, arterial blood gases (ABGs) show pH = 7.2, HCO3 = 12 mEq/L; while, random blood sugar level is 360 mg/dL. What is the likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Congenital hyperplasia","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Acute renal failure","correct":false,"visible":false}]},{"id":8056,"text":"An instructor asked a question in a tutorial class about the histology of the pancreas after discussion. Alpha cells are primarily found in the ____________ of the islet, while beta cells are usually found in the ____________ of the islet.","explanation":null,"reference":null,"responses":[{"text":"Equally in both regions, equally in both regions","correct":false,"visible":false},{"text":"Periphery, center","correct":true,"visible":false},{"text":"Center, equally in both regions","correct":false,"visible":false},{"text":"Equally in both regions, periphery","correct":false,"visible":false},{"text":"Center, periphery","correct":false,"visible":false}]},{"id":8057,"text":"A 33-year-old woman presents to the endocrine clinic with weight gain, easy bruisability, and fatigue during the 3rd trimester of her pregnancy. On examination, she has high blood pressure and stria on the lower abdomen. Further blood investigations show impaired glucose tolerance on an oral glucose tolerance test. Clinical suspicion of Cushing syndrome is raised and she undergoes further evaluation. Which one of the following physiological changes is seen in the adrenocorticotropic hormone (ACTH) cortisol axis during normal pregnancy?","explanation":null,"reference":null,"responses":[{"text":"Lowered cortisol levels","correct":false,"visible":false},{"text":"Loss of diurnal rhythm of cortisol secretion","correct":false,"visible":false},{"text":"Blunting of cortisol response to dexamethasone suppression test","correct":false,"visible":false},{"text":"Urinary free cortisol levels up to five times the normal (non-pregnancy range)","correct":true,"visible":false},{"text":"Lowered cortisol-binding globulin levels","correct":false,"visible":false}]},{"id":8058,"text":"A 13-year-old girl comes to the outpatient department (OPD) with complaints of increased sweating, weight loss, and an increased appetite for 3 months. There is also a history of intermittent diarrhea for the last 3 months. On examination, she is afebrile, heart rate 130 beats/min, and respiratory rate 24 breaths/min. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Graves disease","correct":true,"visible":false},{"text":"Pheochromocytoma","correct":false,"visible":false},{"text":"Diabetes mellitus","correct":false,"visible":false},{"text":"Celiac disease","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false}]},{"id":8064,"text":"A 35-year-old lady presents with complaints of heat intolerance, weight loss, and swelling in front of the neck. She is also found to have bilaterally protruded eyes. What is the most appropriate terminology used for the protruded eyes in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1089.","responses":[{"text":"Lateral visionary field defect","correct":false,"visible":false},{"text":"Exophthalmos","correct":true,"visible":false},{"text":"Lid lag","correct":false,"visible":false},{"text":"Cretinism","correct":false,"visible":false},{"text":"Myxedema","correct":false,"visible":false}]},{"id":8065,"text":"A known case of Addison's disease has pigmentation on various parts of the body, particularly of the sun-exposed areas and at pressure points, such as the neck, elbows, knees, and knuckles. What is the hormone responsible for this pigmentation?","explanation":null,"reference":null,"responses":[{"text":"Gamma melanocyte stimulating hormone (MSH)","correct":false,"visible":false},{"text":"Beta melanocyte stimulating hormone (MSH)","correct":false,"visible":false},{"text":"Pro-gamma melanocyte stimulating hormone (MSH)","correct":false,"visible":false},{"text":"Alpha melanocyte stimulating hormone (MSH)","correct":true,"visible":false},{"text":"Pro-opiomelanocortin (POMC)","correct":false,"visible":false}]},{"id":8068,"text":"A 40-year-old lady presented in the surgery clinic for follow-up after 6 weeks of thyroid surgery of hot nodule. She was presented with complaints of weight gain, cold intolerance, and bradycardia. On laboratory investigation, her thyroid-stimulating hormone (TSH) was raised, however, T3 and T4 were found to be decreased in concentration. What is the most appropriate cause of symptoms in this patient?","explanation":null,"reference":null,"responses":[{"text":"Non-compliance of medications","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Excessive thyroid tissue resection","correct":true,"visible":false},{"text":"Autoimmune disorder","correct":false,"visible":false},{"text":"Iodine deficiency","correct":false,"visible":false}]},{"id":8074,"text":"An employee of a hospital engaged in cleaning vegetation from the roadside and accidentally ingested a small quantity of herbicidal solution that contained paraquat. Within 2 hours he was admitted to the emergency department of Dow University Hospital. Which of the following best describes his probable signs and symptoms in the emergency department?","explanation":null,"reference":null,"responses":[{"text":"Dyspnea, pulmonary dysfunction, and elevated body temperature","correct":false,"visible":false},{"text":"Hypotension, tachycardia, and respiratory impairment","correct":false,"visible":false},{"text":"Dizziness, nausea, agitation, and hyperreflexia","correct":false,"visible":false},{"text":"Gastrointestinal irritation with hematemesis and bloody stools","correct":true,"visible":false},{"text":"Diarrhea, vomiting, sweating, and weakness","correct":false,"visible":false}]},{"id":8075,"text":"A 35-year-old female come to the outpatient department with complaints of painless neck swelling, which she noticed 3 months back. On examination, it is found to be a 2 x 2 cm, soft, rounded, and non-tender swelling in the central neck, which is moving on deglutition but not on tongue protrusion. What is the most likely clinical diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Thyroglossal cyst","correct":false,"visible":false},{"text":"Dermoid cyst","correct":false,"visible":false},{"text":"Cervical abscess","correct":false,"visible":false},{"text":"Branchial cyst","correct":false,"visible":false},{"text":"Thyroid nodule","correct":true,"visible":false}]},{"id":8076,"text":"Which of the following insulin analogs is a long-acting preparation?","explanation":null,"reference":null,"responses":[{"text":"Neutral protamine Hagedorn (NPH)","correct":false,"visible":false},{"text":"Insulin aspart","correct":false,"visible":false},{"text":"Insulin glargine","correct":true,"visible":false},{"text":"Insulin glulisine","correct":false,"visible":false},{"text":"Insulin lispro","correct":false,"visible":false}]},{"id":8077,"text":"A 25-year-old male came to the outpatient department (OPD) with complaints of intermittent headache and nausea for 4 months. On eye examination, he had impaired vision and diplopia. Laboratory investigations showed a decreased level of thyroid-stimulating hormone (TSH), follicular stimulating hormone (FSH) and luteinizing hormone (LH), and increased levels of prolactin. What is the most appropriate diagnosis for this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1070.","responses":[{"text":"Retinal damage","correct":false,"visible":false},{"text":"Corneal infection","correct":false,"visible":false},{"text":"Hypothalamic ischemia","correct":false,"visible":false},{"text":"Ophthalmic inflammation","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":true,"visible":false}]},{"id":8079,"text":"In the case of foodborne botulism, what is true about the toxicity of the organism involved?","explanation":null,"reference":null,"responses":[{"text":"Formed in the colon","correct":false,"visible":false},{"text":"Acts by gastrointestinal irritation","correct":false,"visible":false},{"text":"Formed in the canned food","correct":true,"visible":false},{"text":"Formed in the intestine","correct":false,"visible":false},{"text":"Formed in the duodenum","correct":false,"visible":false}]},{"id":8081,"text":"A 44-year-old male, with no prior comorbidities, presents with body aches and fatigue. His lab results show: parathyroid hormone (PTH) = 103 pg/mL (10-65), Ca 9.0  mg/dl (8.5-10.0), PO4 = 3.0  mg/dl (2.5-5.0), albumin = 4.4 g/dL (2.5-5.5), alkaline phosphatase = 243 IU/L (\u003c 125), and vitamin D = 8.0 ng/mL (\u003e 30). What is the most probable cause?","explanation":null,"reference":null,"responses":[{"text":"Secondary hyperparathyroidism","correct":true,"visible":false},{"text":"Malignancy associated hypercalcemia","correct":false,"visible":false},{"text":"Familial hypocalciuric hypercalcemia","correct":false,"visible":false},{"text":"Primary hyperparathyroidism","correct":false,"visible":false},{"text":"Vitamin D intoxication","correct":false,"visible":false}]},{"id":8195,"text":"A 22-year-old male presents to the clinic with complaints of weight loss, diarrhea, and tremors for the past 2 months. He also complains of excessive sweating and palpitations during his commute to his office in the morning. He smokes 1 pack of cigarettes per day. His sister suffers from Hashimoto thyroiditis. His primary physician orders certain laboratory tests. The results are: thyroid-stimulating hormone (TSH) = 0.002 mIU/L (0.4-4.2), and serum T4 = 23.8 ng/mL (5.5-11.5). What is the interpretation of his laboratory results?","explanation":null,"reference":null,"responses":[{"text":"Biochemical hypothyroidism","correct":false,"visible":false},{"text":"Thyrotoxicosis","correct":true,"visible":false},{"text":"Biochemical hyperthyroidism","correct":false,"visible":false},{"text":"Multinodular goiter","correct":false,"visible":false},{"text":"Iodine toxicity","correct":false,"visible":false}]},{"id":8197,"text":"A 48-year-old, white female complains of progressive weakness, lethargy, and cold intolerance. She also complains of weight gain, coarsening of facial features, hair loss, and increasing hoarseness of her voice. Laboratory results show low levels of T3 and T4 and high thyroid-stimulating hormone (TSH) levels. Which drug is the most appropriate?","explanation":null,"reference":null,"responses":[{"text":"Triiodotyrosine","correct":false,"visible":false},{"text":"Levothyroxine","correct":true,"visible":false},{"text":"Potassium iodide","correct":false,"visible":false},{"text":"Liotrix","correct":false,"visible":false},{"text":"Methimazole","correct":false,"visible":false}]},{"id":8199,"text":"Which of the following is the most common adverse effect of thioamides?","explanation":null,"reference":null,"responses":[{"text":"Hepatitis","correct":false,"visible":false},{"text":"Altered sense of taste or smell","correct":false,"visible":false},{"text":"Agranulocytosis","correct":false,"visible":false},{"text":"Cholestatic jaundice","correct":false,"visible":false},{"text":"Maculopapular pruritic rash","correct":true,"visible":false}]},{"id":8201,"text":"An old lady living alone has locked her room door, but she keeps checking whether the door is locked or not every 5 minutes. Which of the following conditions is she most likely to be suffering from?","explanation":null,"reference":"Le, Tao, and Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed., McGraw-Hill Education, 2021: 586","responses":[{"text":"Delirium","correct":false,"visible":false},{"text":"Obsessive-compulsive disorder","correct":true,"visible":false},{"text":"Delusion of influence","correct":false,"visible":false},{"text":"Paranoid delusions","correct":false,"visible":false},{"text":"Auditory hallucinations","correct":false,"visible":false}]},{"id":8204,"text":"A couple brings their 13-year-old son to the outpatient department because he has not developed secondary sexual characters yet. On examination, testicular volume is 1.6 ml and penis size is 2.5 cm. According to the above examination, this child belongs to which of the following Tanner’s stages?","explanation":null,"reference":null,"responses":[{"text":"I","correct":true,"visible":false},{"text":"II","correct":false,"visible":false},{"text":"IV","correct":false,"visible":false},{"text":"V","correct":false,"visible":false},{"text":"III","correct":false,"visible":false}]},{"id":8206,"text":"Calcimimetics like cinacalcet that are used for the treatment of secondary hyperparathyroidism can act by which of the following mechanisms?","explanation":null,"reference":null,"responses":[{"text":"Decreased expression of the parathyroid hormones receptors","correct":false,"visible":false},{"text":"Increased peripheral metabolism of parathyroid hormone","correct":false,"visible":false},{"text":"Decreased parathyroid hormone secretion from parathyroid gland","correct":true,"visible":false},{"text":"Increased renal excretion of the parathyroid hormones","correct":false,"visible":false},{"text":"Decreased peripheral tissue responses of parathyroid hormone","correct":false,"visible":false}]},{"id":8212,"text":"Thyroid hormone preparations like levothyroxine act on which of the following receptors?","explanation":null,"reference":null,"responses":[{"text":"Ion channel-linked receptors","correct":false,"visible":false},{"text":"Intracellular receptors","correct":true,"visible":false},{"text":"G-protein linked receptors","correct":false,"visible":false},{"text":"Tyrosine kinase receptors","correct":false,"visible":false},{"text":"Cytokine receptors","correct":false,"visible":false}]},{"id":8213,"text":"A couple brings their 12-year-old daughter to the clinic because she has not developed secondary sexual characters yet. On examination, there is no glandular tissue, areola follows the skin contours, and no pubic hair is seen. According to the above examination, this child belongs to which of the following Tanner’s stages?","explanation":null,"reference":null,"responses":[{"text":"II","correct":false,"visible":false},{"text":"V","correct":false,"visible":false},{"text":"III","correct":false,"visible":false},{"text":"I","correct":true,"visible":false},{"text":"IV","correct":false,"visible":false}]},{"id":8214,"text":"Toxicity that stems from exposure to parathion is treated with which of the following?","explanation":null,"reference":null,"responses":[{"text":"Antiseizure drugs","correct":false,"visible":false},{"text":"Hyperbaric oxygen","correct":false,"visible":false},{"text":"Measures to reduce pulmonary edema","correct":false,"visible":false},{"text":"Hemodialysis","correct":false,"visible":false},{"text":"Atropine and pralidoxime","correct":true,"visible":false}]},{"id":8217,"text":"What is the insulin preparation of choice in diabetic ketoacidosis?","explanation":null,"reference":"Ralston, Stuart H., et al., editors. Davidson’s Principles and Practice of Medicine. 23rd ed., Elsevier, 2018: 737.","responses":[{"text":"Lente insulin","correct":false,"visible":false},{"text":"Glargine","correct":false,"visible":false},{"text":"Regular insulin","correct":true,"visible":false},{"text":"Isophane insulin","correct":false,"visible":false},{"text":"Miglitol","correct":false,"visible":false}]},{"id":8219,"text":"A 28-year-old woman presents to the endocrine clinic with secondary amenorrhea and galactorrhoea for the last 6 months. Her general physical and systemic examination is normal. Lab investigations reveal: prolactin = 3250 mU/L (60–620), free T4 = 15.5 pmol/L (11.5–22.7), thyroid-stimulating hormone (TSH) = 2.5 mU/L (0.35–5.5), and urine pregnancy test is negative. Magnetic resonance imaging (MRI) of the pituitary gland confirms the presence of a microadenoma. She is very keen to start a family in the near future and has sought advice regarding further management. Which of the following is the most appropriate therapeutic option in her case?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 683.","responses":[{"text":"Radiotherapy","correct":false,"visible":false},{"text":"Quinagolide","correct":false,"visible":false},{"text":"Elective transsphenoidal surgery","correct":false,"visible":false},{"text":"Bromocriptine","correct":true,"visible":false},{"text":"Octreotide","correct":false,"visible":false}]},{"id":8222,"text":"How does triiodothyronine (T3) differ from thyroxine (T4)?","explanation":null,"reference":null,"responses":[{"text":"It has less risk of cardiotoxicity","correct":false,"visible":false},{"text":"It is less potent","correct":false,"visible":false},{"text":"It is difficult to monitor","correct":true,"visible":false},{"text":"It is given once daily/weekly","correct":false,"visible":false},{"text":"It is mainly preferred in thyroid storm","correct":false,"visible":false}]},{"id":8224,"text":"What is the primary role of the parathyroid gland?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 340.","responses":[{"text":"To send hormonal signals to other endocrine organs","correct":false,"visible":false},{"text":"To preserve bone mass","correct":false,"visible":false},{"text":"To regulate serum calcium levels","correct":true,"visible":false},{"text":"To maintain metabolic homeostasis","correct":false,"visible":false},{"text":"To receive hormonal signals from the hypothalamus","correct":false,"visible":false}]},{"id":8225,"text":"A young patient comes to the emergency room (ER) with intense thirst and dehydration, a blood sugar of 608 mg/dl, serum osmolarity of 300 mOsmol/kg, and pH of 7.1. He is breathing rapidly and his breath emits a fruity smell. What is the diagnosis based on these findings?","explanation":null,"reference":"Sha, Mizaj Shabil, et al. “Breath Analysis for the In Vivo Detection of Diabetic\r\nKetoacidosis.” ACS Omega, 24 Jan. 2022, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8830064/.","responses":[{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Hyperosmolar hyperglycemic nonketotic coma","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Diabetic neuropathy","correct":false,"visible":false},{"text":"Acute renal failure","correct":false,"visible":false}]},{"id":8228,"text":"Which one of the following is the most appropriate screening test for the diagnosis of Cushing’s syndrome in pregnancy?","explanation":null,"reference":null,"responses":[{"text":"Insulin tolerance test","correct":false,"visible":false},{"text":"24-hour urinary free cortisol","correct":true,"visible":false},{"text":"Salivary cortisol","correct":false,"visible":false},{"text":"High-dose dexamethasone test","correct":false,"visible":false},{"text":"Computed tomography (CT) adrenals","correct":false,"visible":false}]},{"id":8230,"text":"A 35-year-old female presents to the clinic with complaints of vertigo, severe weakness, and bradycardia. On taking history,  she had an assisted vaginal delivery 1 month back and hospitalization of 1 week postpartum. What is the most likely diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Metabolic syndrome","correct":false,"visible":false},{"text":"Adenomatous polyposis syndrome","correct":false,"visible":false},{"text":"MEN syndrome","correct":false,"visible":false},{"text":"Sheehan syndrome","correct":true,"visible":false}]},{"id":8233,"text":"What is the most common cause of primary hypoparathyroidism?","explanation":null,"reference":null,"responses":[{"text":"Renal failure","correct":false,"visible":false},{"text":"Adenoma","correct":false,"visible":false},{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Thyroid surgery","correct":true,"visible":false}]},{"id":8234,"text":"A 38-year-old woman presents to the clinic with a history of end-stage renal disease secondary to hypertension. She has undergone dialysis 3 times weekly for the last 5 years and her medical records show progressive elevation of calcium levels over the last year. On physical examination, Body Mass Index (BMI) is 22.5 kg/m², blood pressure (BP) is 145/98 mmHg, and pulse rate is 91 beats/min. Laboratory test results: total calcium= 11.9 mg/dL (8.2-10 .2 mg/dL), phosphorus= 6.7 mg/dL (2.3-4.7 mg/dL), creatinine = 9.3 mg/dL (0.6-1.1 mg/dL), alkaline phosphatase = 1181 U/L (50-120 U/L). What is the most likely cause of her hypercalcemia?","explanation":null,"reference":null,"responses":[{"text":"Malignancy associated hypercalcemia","correct":false,"visible":false},{"text":"Tertiary hyperparathyroidism","correct":true,"visible":false},{"text":"Parathyroid nodular hyperplasia","correct":false,"visible":false},{"text":"Familial hypocalciuric hypercalcemia","correct":false,"visible":false},{"text":"Parathyroid carcinoma","correct":false,"visible":false}]},{"id":8235,"text":"Which of the following hormones is secreted in large quantities from the zona fasciculata of the adrenal gland?","explanation":"The adrenal cortex, which is divided into three distinct layers (zona glomerulosa, zona fasciculata, and zona reticularis), produces various hormones. The **zona fasciculata** is responsible for the production and secretion of **cortisol**, a glucocorticoid hormone that plays a critical role in regulating metabolism, immune response, and the body's response to stress.\r\n\r\n***\r\n\r\nEstrogen is primarily produced by the ovaries in females, although it is also produced in smaller quantities by the adrenal glands and adipose tissues.\r\n\r\nAdrenocorticotropic hormone (ACTH) is produced by the anterior pituitary gland and stimulates the adrenal cortex, including the zona fasciculata, to produce cortisol.\r\n\r\nAndrogens, such as testosterone, are primarily produced by the testes in males and to a lesser extent by the adrenal glands in both males and females.\r\n\r\nAldosterone is mainly produced in the zona glomerulosa of the adrenal cortex and plays a key role in regulating electrolyte and fluid balance, particularly sodium and potassium levels.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier; 2020: 966.","responses":[{"text":"Androgen","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false}]},{"id":8236,"text":"Acute toxicity of organophosphate causes which of the following conditions?","explanation":null,"reference":null,"responses":[{"text":"Urinary incontinence","correct":true,"visible":false},{"text":"Anuria","correct":false,"visible":false},{"text":"Hematuria","correct":false,"visible":false},{"text":"Oliguria","correct":false,"visible":false},{"text":"Urinary retention","correct":false,"visible":false}]},{"id":8237,"text":"A farmer’s wife while picking cotton from cotton pods develops nausea and dyspnea. When taken to hospital she was diagnosed with organophosphorus poisoning. What is the most likely route of entry of poison in this patient?","explanation":null,"reference":null,"responses":[{"text":"Gastrointestinal","correct":false,"visible":false},{"text":"Inhalation","correct":false,"visible":false},{"text":"Contact with mucous membrane","correct":false,"visible":false},{"text":"Contact with intact skin","correct":true,"visible":false},{"text":"Eyes","correct":false,"visible":false}]},{"id":8238,"text":"A 34-year-old man receiving medication for hyperthyroidism has a rash, pruritus, fever, diarrhea, bitter taste in his mouth, and feelings of anxiety. Which of the following drugs is most likely causing these symptoms?","explanation":null,"reference":null,"responses":[{"text":"Diatrizoate","correct":false,"visible":false},{"text":"Potassium iodide","correct":true,"visible":false},{"text":"Propylthiouracil","correct":false,"visible":false},{"text":"Propranolol","correct":false,"visible":false},{"text":"Radioactive iodine","correct":false,"visible":false}]},{"id":8239,"text":"A 55-year-old female comes to the clinic with complaints of polyuria, polydipsia, and polyphagia. Laboratory investigations were done. What are the confirmed values that meet the diagnostic threshold for diabetes?","explanation":null,"reference":null,"responses":[{"text":"Fasting blood glucose ≥ 126 mg/dl","correct":true,"visible":false},{"text":"2-hour post prandial glucose ≥ to 126 mg/dl","correct":false,"visible":false},{"text":"Random blood glucose \u003e 160 mg/dl","correct":false,"visible":false},{"text":"Fasting blood glucose ≥ 100 mg/dl","correct":false,"visible":false},{"text":"Fasting blood glucose = 140 mg/dl","correct":false,"visible":false}]},{"id":8240,"text":"The anti-inflammatory effects of glucocorticoids are due to which fundamental mechanism?","explanation":null,"reference":null,"responses":[{"text":"Decrease T-cell function","correct":false,"visible":false},{"text":"Increase capillary permeability","correct":false,"visible":false},{"text":"Simulate histamine release from mast cells","correct":false,"visible":false},{"text":"Inhibit macrophage phagocytosis","correct":false,"visible":false},{"text":"Inhibit leukotriene and prostaglandin synthesis via inhibition of phospholipase A2","correct":true,"visible":false}]},{"id":8241,"text":"A patient has been taking systemic corticosteroids for a certain condition for quite some time now due to which he has developed a lot of adverse effects. Which one of the following adverse effects is most likely due to its mineralocorticoid action?","explanation":null,"reference":null,"responses":[{"text":"Hypertension","correct":true,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Moon-like face","correct":false,"visible":false},{"text":"Increased susceptibility to infections","correct":false,"visible":false}]},{"id":8242,"text":"Laboratory work for a 65-year-old patient with diabetes comes back with a serum blood sugar of 950 mg/dl and serum osmolarity of 460 mOsmol/kg. The patient is confused and dehydrated. What is this condition known as?","explanation":null,"reference":null,"responses":[{"text":"Diabetic nephropathy","correct":false,"visible":false},{"text":"Renal tubular acidosis","correct":false,"visible":false},{"text":"Diabetic neuropathy","correct":false,"visible":false},{"text":"Hyperosmolar hyperglycemic nonketotic coma","correct":true,"visible":false},{"text":"Diabetic ketoacidosis","correct":false,"visible":false}]},{"id":8243,"text":"A 25-year-old lady presents to the endocrine clinic with complaints of weight loss, excessive sweating, tachycardia, and tremors. She was diagnosed with hyperthyroidism after some laboratory investigations. What is the most appropriate cause of tremors in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1084.","responses":[{"text":"Sub cutaneous accumulation of matrix","correct":false,"visible":false},{"text":"Weakness","correct":false,"visible":false},{"text":"Sympathetic nervous system stimulation","correct":true,"visible":false},{"text":"Increased cardiac output","correct":false,"visible":false},{"text":"Psychological disorder","correct":false,"visible":false}]},{"id":8244,"text":"Which of the following is a macrovascular complication of diabetes?","explanation":null,"reference":null,"responses":[{"text":"Retinopathy","correct":false,"visible":false},{"text":"Nephropathy","correct":false,"visible":false},{"text":"Peripheral arterial disease","correct":true,"visible":false},{"text":"Neuropathy","correct":false,"visible":false},{"text":"Decline in β-cell function","correct":false,"visible":false}]},{"id":8245,"text":"A 60-year-old male has increased blood pressure, heart rate, and signs of heart failure. He was diagnosed with a tumor involving the adrenal cortex. Which part of the adrenal cortex is probably involved?","explanation":null,"reference":null,"responses":[{"text":"Spongiocytes","correct":false,"visible":false},{"text":"Zona glomerulosa","correct":true,"visible":false},{"text":"Zona fasciculata","correct":false,"visible":false},{"text":"Zona reticularis","correct":false,"visible":false},{"text":"Chromaffin cells","correct":false,"visible":false}]},{"id":8246,"text":"The statement “weight loss despite a good appetite” is the best fit for which of the following conditions?","explanation":null,"reference":null,"responses":[{"text":"Hypoparathyroidism","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":true,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Hyperaldosteronism","correct":false,"visible":false}]},{"id":8247,"text":"A couple brings their 6-year-old daughter to the outpatient department. Her bilateral breast bud formation started two months ago. On examination, breast buds are observed with a small area of surrounding glandular tissue. Areolas have begun to widen. According to the above examination, this child belongs to which of the following Tanner’s stages?","explanation":null,"reference":null,"responses":[{"text":"II","correct":true,"visible":false},{"text":"IV","correct":false,"visible":false},{"text":"V","correct":false,"visible":false},{"text":"III","correct":false,"visible":false},{"text":"I","correct":false,"visible":false}]},{"id":8248,"text":"A drug addict keeps scratching his body and complains that he feels insects creeping on his body. What is he suffering from?","explanation":null,"reference":"Le T, Bhushan V, Qiu C, et al., eds. First Aid for the USMLE Step 1 2023. 33rd ed. McGraw Hill; 2023: 578.","responses":[{"text":"Illusions","correct":false,"visible":false},{"text":"Auditory hallucinations","correct":false,"visible":false},{"text":"Tactile hallucinations","correct":true,"visible":false},{"text":"Paranoid delusion","correct":false,"visible":false},{"text":"Visual hallucinations","correct":false,"visible":false}]},{"id":8249,"text":"Which one of the following oral hypoglycemic agents decreases the rate of liver glucose production, and augments glucose uptake by tissues and lowers lipids?","explanation":null,"reference":null,"responses":[{"text":"Nateglinide","correct":false,"visible":false},{"text":"Miglitol","correct":false,"visible":false},{"text":"Repaglinide","correct":false,"visible":false},{"text":"Pioglitazone","correct":false,"visible":false},{"text":"Metformin","correct":true,"visible":false}]},{"id":8250,"text":"Amongst the endogenous causes of Cushing syndrome, what is the most common one?","explanation":null,"reference":null,"responses":[{"text":"Ectopic ACTH secretion","correct":false,"visible":false},{"text":"Iatrogenic","correct":false,"visible":false},{"text":"Cushing disease","correct":true,"visible":false},{"text":"Adrenocortical hyperplasia","correct":false,"visible":false},{"text":"Pseudo-Cushing Syndrome","correct":false,"visible":false}]},{"id":8251,"text":"Which of the following oral antidiabetic agents stimulates beta cells to secrete more insulin?","explanation":null,"reference":null,"responses":[{"text":"Sulfonylureas","correct":true,"visible":false},{"text":"Biguanides","correct":false,"visible":false},{"text":"Alpha-glucosidase inhibitors","correct":false,"visible":false},{"text":"Meglitnides","correct":false,"visible":false},{"text":"Thiazolidinediones","correct":false,"visible":false}]},{"id":8252,"text":"A farmer while spraying his fields fell suddenly ill and was brought to the emergency department, with complaints of nausea, dyspnea, chest pain, muscle cramps, and blurred vision. What is the antidote of choice for the above-mentioned poisoning?","explanation":null,"reference":null,"responses":[{"text":"Cholinesterase","correct":false,"visible":false},{"text":"Atropine","correct":true,"visible":false},{"text":"Pralidoxime","correct":false,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Obidoxime","correct":false,"visible":false}]},{"id":8258,"text":"Which of the following structures is not included in the superior relations of the pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Optic chiasma","correct":false,"visible":false},{"text":"Diaphragma sellae","correct":false,"visible":false},{"text":"Sphenoid air sinuses","correct":true,"visible":false},{"text":"Tuber cinereum","correct":false,"visible":false},{"text":"Infundibular recess of the third ventricle","correct":false,"visible":false}]},{"id":8262,"text":"A 30-year-old woman presents to the clinic with palpitations, weight loss, and excessive sweating for almost 5-6 months. She cannot concentrate on carrying out her daily activities especially looking after her children. Recently, she also developed pain in both eyes and her friend told her that one of her eyes has become more prominent than the other. What is the most likely cause of her condition?","explanation":"The patient's symptoms, including palpitations, weight loss, excessive sweating, inability to concentrate, and prominent eyes, are characteristic of **hyperthyroidism**. Grave's disease is an autoimmune disorder where the immune system produces antibodies that stimulate the thyroid gland to produce excessive amounts of thyroid hormones.\r\n\r\nCommon clinical features of Grave's disease include:\r\n\r\n1. **Palpitations**: Due to an increased heart rate and cardiac output caused by elevated thyroid hormones.\r\n\r\n2. **Weight loss**: Hyperthyroidism increases metabolic rate, leading to unintended weight loss.\r\n\r\n3. **Excessive sweating**: Hyperthyroidism increases sympathetic nervous system activity, leading to increased sweating.\r\n\r\n4. **Inability to concentrate**: Excessive thyroid hormones can affect mental function and cause difficulty in focusing.\r\n\r\n5. **Prominent eyes (exophthalmos)**: Grave's disease can lead to swelling of the tissues behind the eyes, causing the eyes to bulge forward.\r\n\r\nThe combination of these symptoms strongly suggests Grave's disease as the underlying cause of her condition.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1081-1082.","responses":[{"text":"Grave’s disease","correct":true,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Hashimoto’s thyroiditis","correct":false,"visible":false},{"text":"Toxic nodular goiter","correct":false,"visible":false},{"text":"Generalized anxiety disorder","correct":false,"visible":false}]},{"id":8264,"text":"A 42-year-old woman was incidentally detected to have a 2-cm left adrenal gland mass while she underwent computed tomography (CT) of the abdomen to investigate the cause of her pelvic pain and menstrual irregularities. Which one of the following is the most common cause of an incidentally detected adrenal mass?","explanation":null,"reference":null,"responses":[{"text":"Subclinical Cushing’s disease","correct":false,"visible":false},{"text":"Conn’s syndrome","correct":false,"visible":false},{"text":"Adrenocortical carcinoma","correct":false,"visible":false},{"text":"Non-functional adenoma","correct":true,"visible":false},{"text":"Adrenal metastasis","correct":false,"visible":false}]},{"id":8266,"text":"A man, charged with murder, pleaded insanity in a court of law. He was brought before the medical officer for examination. How will the medical officer differentiate between true and feigned insanity?","explanation":null,"reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 408.","responses":[{"text":"In feigned insanity peculiar facial expressions are absent","correct":true,"visible":false},{"text":"In feigned insanity the person appreciates repeated examination","correct":false,"visible":false},{"text":"In feigned insanity fatigue does not set in","correct":false,"visible":false},{"text":"In feigned insanity behavioral disturbances are uniform","correct":false,"visible":false},{"text":"In feigned insanity the onset is gradual","correct":false,"visible":false}]},{"id":8267,"text":"A 6-year-old boy is brought to the emergency department with complaints of gastric irritation, nausea, vomiting, and abdominal pain. He also complains of burning sensation in the urethra, pain in loins, and passing black-colored urine. What is the most probable cause for the above-mentioned symptoms?","explanation":null,"reference":null,"responses":[{"text":"Endrin poisoning","correct":false,"visible":false},{"text":"Naphthalene poisoning","correct":true,"visible":false},{"text":"Carbonate poisoning","correct":false,"visible":false},{"text":"Organophosphorus poisoning","correct":false,"visible":false},{"text":"Paraquat poisoning","correct":false,"visible":false}]},{"id":8268,"text":"A 35-year-old lady is diagnosed with autoimmune hypothyroidism. Her physician was concerned about thyroid auto-antibodies. Which of the following is the most appropriate antibody to detect the autoimmune thyroid disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1085.","responses":[{"text":"Anti-membrane","correct":false,"visible":false},{"text":"Anti-follicular","correct":false,"visible":false},{"text":"Anti-peroxidase","correct":true,"visible":false},{"text":"Anti-cytoplasmic","correct":false,"visible":false},{"text":"Anti-nuclear","correct":false,"visible":false}]},{"id":8269,"text":"A 32-year-old lady presents to the clinic with an inability to lactate and amenorrhea for the last 9-10 months. She delivered a baby boy almost 10 months back, during which she experienced a lot of blood loss requiring blood transfusion. She also complains of lethargy, fatigue, and is unable to take care of her baby adequately. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Pituitary apoplexy","correct":false,"visible":false},{"text":"Empty sella syndrome","correct":false,"visible":false},{"text":"Idiopathic hypogonadotropic hypogonadism","correct":false,"visible":false},{"text":"Hypopituitarism","correct":false,"visible":false},{"text":"Sheehan’s syndrome","correct":true,"visible":false}]},{"id":8270,"text":"Which of the following substances stimulates glucagon secretion?","explanation":null,"reference":null,"responses":[{"text":"Increased fatty acids","correct":false,"visible":false},{"text":"Somatostatin","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Arginine","correct":true,"visible":false},{"text":"Na+","correct":false,"visible":false}]},{"id":8271,"text":"What is the most common cause of hypercalcemia?","explanation":null,"reference":null,"responses":[{"text":"Secondary hyperparathyroidism","correct":false,"visible":false},{"text":"Primary hyperparathyroidism","correct":true,"visible":false},{"text":"Tertiary hyperparathyroidism","correct":false,"visible":false},{"text":"Vitamin D toxicity","correct":false,"visible":false},{"text":"Humoral hypercalcemia of malignancy","correct":false,"visible":false}]},{"id":8272,"text":"A 32-year-old man was diagnosed with type 1 diabetes mellitus (DM) 5 years ago and was previously well controlled on insulin glargine and insulin lispro. He attended the endocrine clinic after a year, with a recent deterioration of his blood sugar levels. He complained of excessive sweating, weight gain, headaches, and decreased libido. He had to buy new pair of shoes 3 times over the last year because they became too small very soon. On examination, he has acanthosis, and there are a number of skin tags around his neck. Apart from diabetes evaluation, what single investigation is useful to assess his recent symptoms?","explanation":null,"reference":null,"responses":[{"text":"Growth hormone level","correct":false,"visible":false},{"text":"Serum testosterone level","correct":false,"visible":false},{"text":"Serum IGF-1 level","correct":true,"visible":false},{"text":"HemoglobinA1C level","correct":false,"visible":false},{"text":"Random cortisol level","correct":false,"visible":false}]},{"id":8273,"text":"Inhaled corticosteroids are preferred for asthma as they rarely cause adverse effects. What is the reason for this?","explanation":null,"reference":null,"responses":[{"text":"They are quickly eliminated by the kidney","correct":false,"visible":false},{"text":"The amount of drug reaching the systemic circulation is very small","correct":true,"visible":false},{"text":"They are completely metabolized by the lung","correct":false,"visible":false},{"text":"They are rapidly redistributed","correct":false,"visible":false},{"text":"They are completely eliminated with the exhaled air","correct":false,"visible":false}]},{"id":8274,"text":"A 5-year girl presents to a rural dispensary in Pakistan with height and weight \u003c2nd percentile and 3rd percentile, respectively. There is no significant family history. Clinical examination is otherwise unremarkable. Which of the following conditions is the most likely cause of short stature in this girl?","explanation":null,"reference":null,"responses":[{"text":"Growth hormone (GH) deficiency","correct":false,"visible":false},{"text":"Familial short stature","correct":false,"visible":false},{"text":"Turner syndrome","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Malnutrition","correct":true,"visible":false}]},{"id":8275,"text":"A 30-year-old female comes to the clinic with the complaint of painless swelling on the left side of the neck for 3 months. Detailed history and examination reveal she has palpitations, heat intolerance, sweating, and frequent diarrhea. Her pulse is 110 beats/min, blood pressure is 110/80 mmHg. Her palms are moist but no tremors are observed. There is about 4 x 4 cm, soft, non-tender, swelling on the left side of the neck, which is moving upon deglutition. She has decreased thyroid-stimulating hormone (TSH) levels with increased free T3 and T4 levels. What is the most likely clinical diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Toxic thyroid nodule","correct":true,"visible":false},{"text":"Toxic multinodular goiter","correct":false,"visible":false},{"text":"Solitary nodule thyroid","correct":false,"visible":false},{"text":"Multinodular goiter","correct":false,"visible":false},{"text":"Thyroglossal cyst","correct":false,"visible":false}]},{"id":8276,"text":"A 45-year-old woman presents to the clinic with irregular menses for 5 months. She sometimes experiences heavy menstrual flow and consults her gynecologist for this. Her weight is increasing steadily over the past year and she becomes fatigued after minor house chores. Her gynecologist advised thyroid function tests and referred her to an endocrinologist for further management. On examination, her body mass index (BMI) is 29 kg/m2, and her blood pressure is 135/98 mmHg. Following are the lab results: thyroid-stimulating hormone (TSH): 6.6 mIU/L (0.4-4.2), serum T4: 6.8 ng/ml (5.5-11.5), anti-thyroid peroxidase antibodies: 223 IU/L (\u003c35). What is the biochemical interpretation of her lab results?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 642.","responses":[{"text":"Iodine deficiency","correct":false,"visible":false},{"text":"Primary hypothyroidism","correct":false,"visible":false},{"text":"Subclinical hyperthyroidism","correct":false,"visible":false},{"text":"Subclinical hypothyroidism","correct":true,"visible":false},{"text":"Hashimoto’s thyroiditis","correct":false,"visible":false}]},{"id":8278,"text":"A 36-year-old female presents to the clinic with complaints of secondary amenorrhea and headache for 6 months. She has 3 children, the last-born is 2 years old. She has also noted weight gain during the same time period. On examination, there is mild hirsutism, secondary sexual characteristics were well developed and there is expressive galactorrhea. However, visual confrontation shows left inferior temporal field defects. Serum thyroid-stimulating hormone (TSH) is 2.4 (0.4-4.0), luteinizing hormone (LH) is 0.2 (1.2-4.0), follicular stimulating hormone (FSH) is 2.0 (2.0-8.0) and prolactin levels are 90 (10-23). What is the possible cause of her presentation?","explanation":null,"reference":null,"responses":[{"text":"Prolactinoma","correct":true,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Polycystic ovary syndrome","correct":false,"visible":false},{"text":"Secondary hypogonadism","correct":false,"visible":false},{"text":"Lactational amenorrhea","correct":false,"visible":false}]},{"id":8281,"text":"Which of the following is necessary for the release of insulin from beta cells of the pancreas?","explanation":null,"reference":null,"responses":[{"text":"Mg++","correct":false,"visible":false},{"text":"Na+","correct":false,"visible":false},{"text":"Ca++","correct":true,"visible":false},{"text":"HCO3-","correct":false,"visible":false},{"text":"CL-","correct":false,"visible":false}]},{"id":8284,"text":"A 26-year-old woman is complaining of an abnormal tingling sensation in her hands and feet. For the last 2 years, a neurologist is treating her for a seizure disorder. On examination, her blood pressure (BP) is 125/77 mmHg and her pulse is 98 beats/min. Her investigations show: calcium = 6.5 (7.5-8.5 mg/dL), phosphate = 4.8 (2.5-4.0 mg/dL). What is the most likely cause of her hypocalcemia?","explanation":null,"reference":null,"responses":[{"text":"Primary hypoparathyroidism","correct":true,"visible":false},{"text":"Pseudohypoparathyroidism","correct":false,"visible":false},{"text":"Malabsorption syndrome","correct":false,"visible":false},{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Phenytoin toxicity","correct":false,"visible":false}]},{"id":8285,"text":"Which of the following statements is correct about the pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Pituicytes in the posterior pituitary are a type of neuroglial cells","correct":true,"visible":false},{"text":"Hypophyseal portal system is responsible for carrying oxytocin and ADH from hypothalamic nuclei to the posterior pituitary","correct":false,"visible":false},{"text":"Pars distalis is part of posterior pituitary","correct":false,"visible":false},{"text":"Anterior pituitary develops from downgrowth from hypothalamus","correct":false,"visible":false},{"text":"Pars intermedia is concerned with secreting oxytocin","correct":false,"visible":false}]},{"id":8288,"text":"All of the following antidiabetic agents are matched with their classification. Which of the pairings is incorrect?","explanation":null,"reference":null,"responses":[{"text":"Acarbose: alpha glucosidase inhibitor","correct":false,"visible":false},{"text":"Glyburide: sulfonylurea","correct":false,"visible":false},{"text":"Repaglinide: thiazolidinedione","correct":true,"visible":false},{"text":"Metformin: biguanide","correct":false,"visible":false},{"text":"Nateglinide: phenylalanine derivative","correct":false,"visible":false}]},{"id":8293,"text":"A patient presents with weakness, easy fatigability, gastrointestinal disturbances, and hyperpigmentation. Features are suggestive of adrenal insufficiency. What should be the time of sample collection for adrenal insufficiency?","explanation":null,"reference":null,"responses":[{"text":"Afternoon around 2:00 pm","correct":false,"visible":false},{"text":"Evening around 8:00 pm","correct":false,"visible":false},{"text":"Late evening","correct":false,"visible":false},{"text":"Morning around 8:00 am","correct":true,"visible":false},{"text":"Night around 11:00 pm","correct":false,"visible":false}]},{"id":8295,"text":"A 25-year-old lady is found to be tachycardic during her pre-employment checkup. Further examination reveals a 3 x 3 cm non-tender swelling on the right side of the neck, which is moving on deglutition. Her thyroid profile was subsequently requested, which revealed thyroid-stimulating hormone (TSH) \u003c 0.004 mIU/L (N~ 0.5-5) and free T3: 35 pmol/L (range 10.3-24.0pmol/L). What would be the most appropriate next investigation in this patient?","explanation":null,"reference":null,"responses":[{"text":"Fine needle aspiration cytology (FNAC)","correct":false,"visible":false},{"text":"Isotope scan","correct":true,"visible":false},{"text":"CT scan neck","correct":false,"visible":false},{"text":"Ultrasound neck","correct":false,"visible":false},{"text":"Core biopsy","correct":false,"visible":false}]},{"id":8298,"text":"A couple brings their 6-year-old son to the outpatient department (OPD) after his pubic hair started growing 2 months ago. On examination, testicular volume is around 10 ml, penile length is about 6 cm, and pubic hair is coarse and curly. According to the above examination, this child belongs to which of the following Tanner’s stages?","explanation":null,"reference":null,"responses":[{"text":"I","correct":false,"visible":false},{"text":"II","correct":false,"visible":false},{"text":"IV","correct":false,"visible":false},{"text":"V","correct":false,"visible":false},{"text":"III","correct":true,"visible":false}]},{"id":8610,"text":"A child is brought to the emergency department with a history of ‘alleged’ snake bite. There is no swelling and no bite mark is seen on examination. He is anxious, has dyspnea, and is unable to open his eyes. The blood clotting mechanism observed for 20 minutes is normal. Which of the following is the best initial step in management?","explanation":null,"reference":null,"responses":[{"text":"Give antihistamines","correct":false,"visible":false},{"text":"Give anti snake venom (ASV) and neostigmine","correct":false,"visible":false},{"text":"Do not give anti snake venom (ASV) and observe the patient","correct":false,"visible":false},{"text":"Give anti snake venom (ASV) and observe the patient","correct":false,"visible":false},{"text":"Give anxiolytic and reassure the patient","correct":true,"visible":false}]},{"id":8633,"text":"Which of these is false regarding the pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Adrenocorticotrophic hormone is released by anterior pituitary","correct":false,"visible":false},{"text":"Oxytocin and antidiuretic hormone are released by the posterior pituitary","correct":false,"visible":false},{"text":"Posterior pituitary is called neurohypophysis","correct":false,"visible":false},{"text":"It lies in fossa of the zygomatic bone","correct":true,"visible":false},{"text":"Anterior pituitary is also called the adenohypophysis","correct":false,"visible":false}]},{"id":8668,"text":"A 7-year-old kid presents to the outpatient department with a protruding tongue, mental retardation, umbilical hernia, and coarse facial features. He is diagnosed with cretinism. A deficiency of which hormone can cause this?","explanation":null,"reference":null,"responses":[{"text":"Thyroxine","correct":true,"visible":false},{"text":"Calcitonin","correct":false,"visible":false},{"text":"Somatostatin","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false}]},{"id":10904,"text":"Which of the following is incorrect regarding the use of crystalline zinc regular insulin?","explanation":null,"reference":null,"responses":[{"text":"It is usually administered orally","correct":true,"visible":false},{"text":"Hypoglycemia is the most common adverse effect of regular insulin","correct":false,"visible":false},{"text":"It can be used a replacement therapy for juvenile-onset diabetes","correct":false,"visible":false},{"text":"It is usually administered intravenously","correct":false,"visible":false},{"text":"It is short-acting insulin","correct":false,"visible":false}]},{"id":10905,"text":"A 7-year-old boy picks a seed from the park and chewed and ingested it. He later develops extreme muscle contractions and convulsions. He gets diagnosed with strychnine poisoning. In terms of mechanism of action, which part of the spinal cord does strychnine stimulate?","explanation":null,"reference":null,"responses":[{"text":"Anterior horn cells","correct":true,"visible":false},{"text":"Dorsal column","correct":false,"visible":false},{"text":"Medial fasciculus","correct":false,"visible":false},{"text":"Reflex arc","correct":false,"visible":false},{"text":"Spinothalamic tract","correct":false,"visible":false}]}
]

export default a